/**
 * CommitRequest
 *
 * Wire-level schema for ``POST /ingest/commit/{job_id}``.
 *
 * Preserved as a flat union of all possible commit fields so that the
 * FastAPI route signature renders correctly in OpenAPI and so that the
 * frontend's ``CommitImportRequest`` TypeScript type stays unchanged.
 *
 * The route handler re-validates the body against a subclass chosen by
 * ``_pick_commit_subclass(job)`` (see ``app.ingest.router``):
 *
 * - ``VectorCommitRequest`` — default for file uploads
 * - ``RasterCommitRequest`` — when ``job.user_metadata['file_type'] == 'raster'``
 * - ``ServiceCommitRequest`` — when ``job.source_url`` is set and ``job.file_path`` is None
 *
 * For new internal code that constructs a commit view, prefer importing
 * the appropriate subclass directly. This flat class is the wire contract,
 * not an implementation detail.
 */
export type CommitRequest = {
    /**
     * Compression
     *
     * Raster only: target compression for COG output (e.g. 'LZW', 'DEFLATE').
     */
    compression?: string | null;
    /**
     * Geom Column
     *
     * CSV/Excel only: name of the WKT geometry column (alternative to x_column/y_column).
     */
    geom_column?: string | null;
    /**
     * Layer Name
     *
     * Multi-layer source only: name of the specific layer to ingest.
     */
    layer_name?: string | null;
    /**
     * Nodata Override
     *
     * Raster only: nodata value to use when source has none defined.
     */
    nodata_override?: number | string | null;
    /**
     * Resampling
     *
     * Raster only: resampling method for COG conversion (e.g. 'nearest', 'bilinear', 'cubic').
     */
    resampling?: string | null;
    /**
     * Srid Override
     *
     * EPSG code to use when source CRS is missing or incorrect. Forces reprojection during ingestion.
     */
    srid_override?: number | null;
    /**
     * Summary
     *
     * Optional dataset description shown in the catalog.
     */
    summary?: string | null;
    /**
     * Temporal End
     *
     * ISO 8601 end of the dataset's temporal extent.
     */
    temporal_end?: string | null;
    /**
     * Temporal Start
     *
     * ISO 8601 start of the dataset's temporal extent.
     */
    temporal_start?: string | null;
    /**
     * Title
     *
     * Human-readable dataset title.
     */
    title: string;
    /**
     * Token
     *
     * Optional confirmation token returned by the preview step. Required for some workflows.
     */
    token?: string | null;
    /**
     * Visibility
     *
     * Dataset visibility level: 'private' (owner-only), 'restricted' (RBAC-controlled), 'internal' (all users), 'public' (anonymous access).
     */
    visibility?: 'private' | 'restricted' | 'internal' | 'public';
    /**
     * X Column
     *
     * CSV/Excel only: name of the longitude/X coordinate column.
     */
    x_column?: string | null;
    /**
     * Y Column
     *
     * CSV/Excel only: name of the latitude/Y coordinate column.
     */
    y_column?: string | null;
};

